import{_ as a,o as l,c as i,ah as o}from"./chunks/framework.Bi9enVNS.js";const m=JSON.parse('{"title":"当前实现边界","description":"","frontmatter":{},"headers":[],"relativePath":"intro/limits.md","filePath":"intro/limits.md","lastUpdated":1774205896000}'),t={name:"intro/limits.md"};function r(d,e,c,n,s,h){return l(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="当前实现边界" tabindex="-1">当前实现边界 <a class="header-anchor" href="#当前实现边界" aria-label="Permalink to &quot;当前实现边界&quot;">​</a></h1><p>这一页记录的是“现在没有什么”，避免把参考实现误读成更完整的平台能力。</p><h2 id="存储与持久化" tabindex="-1">存储与持久化 <a class="header-anchor" href="#存储与持久化" aria-label="Permalink to &quot;存储与持久化&quot;">​</a></h2><ul><li>只提供内存存储实现</li><li>进程重启后数据不会保留</li><li>没有索引、分片、冷热分层或多租户存储策略</li></ul><h2 id="摄取与鉴权" tabindex="-1">摄取与鉴权 <a class="header-anchor" href="#摄取与鉴权" aria-label="Permalink to &quot;摄取与鉴权&quot;">​</a></h2><ul><li>只有一个上传入口：<code>POST /v1/logs</code></li><li>只有 Bearer token 授权，没有更细粒度的用户/角色模型</li><li>token 只按 project 做允许写入控制</li></ul><h2 id="查询能力" tabindex="-1">查询能力 <a class="header-anchor" href="#查询能力" aria-label="Permalink to &quot;查询能力&quot;">​</a></h2><ul><li>查询接口全部返回 JSON</li><li>日志搜索当前只支持固定字段筛选，不支持复杂布尔表达式</li><li><code>keyword</code> 只匹配 <code>body_text + body_json</code>，不匹配 attributes/resource</li><li>没有分页参数，没有排序选项</li></ul><h2 id="trace-与拓扑语义" tabindex="-1">Trace 与拓扑语义 <a class="header-anchor" href="#trace-与拓扑语义" aria-label="Permalink to &quot;Trace 与拓扑语义&quot;">​</a></h2><ul><li>topology 不是 span 关系图，而是根据 Trace 内时间相邻来源段推导</li><li>连续相同来源片段会折叠，避免错误自环</li><li><code>observed_time</code> 会被协议接受，但不会进入当前归一化输出</li></ul><h2 id="幂等与缓存" tabindex="-1">幂等与缓存 <a class="header-anchor" href="#幂等与缓存" aria-label="Permalink to &quot;幂等与缓存&quot;">​</a></h2><ul><li>幂等窗口只在当前进程内维护</li><li>TTL 固定为 24 小时</li><li>幂等键为 <code>project + request_id</code></li></ul><h2 id="前端与部署" tabindex="-1">前端与部署 <a class="header-anchor" href="#前端与部署" aria-label="Permalink to &quot;前端与部署&quot;">​</a></h2><ul><li>当前前端默认请求 <code>http://localhost:8080</code></li><li>文档未包含 CI/CD、生产部署或云托管方案</li></ul><h2 id="事实来源" tabindex="-1">事实来源 <a class="header-anchor" href="#事实来源" aria-label="Permalink to &quot;事实来源&quot;">​</a></h2><ul><li><code>README.md</code></li><li><code>internal/config/config.go</code></li><li><code>internal/ingest/service.go</code></li><li><code>internal/ingest/normalize.go</code></li><li><code>internal/store/memory/memory.go</code></li></ul>',16)])])}const _=a(t,[["render",r]]);export{m as __pageData,_ as default};
